export default defineComponent({
  name: 'NumberAnimation',
  props: numberAnimationProps,
  setup(props) {
    const { localeRef } = useLocale('name')
    const { duration } = props
    const displayedValueRef = ref(props.from)
    const mergedLocaleRef = computed(() => {
      const { locale } = props
      if (locale !== undefined)
        return locale
      return localeRef.value
    })
    let animating = false
    const onUpdate = (currentValue: number): void => {
      displayedValueRef.value = currentValue
    }
    const onFinish = (): void => {
      displayedValueRef.value = props.to
      animating = false
      props.onFinish?.()
    }
    const animate = (
      from: number = props.from,
      to: number = props.to
    ): void => {
      animating = true
      displayedValueRef.value = props.from
      if (from !== to) {
        tween({
          from,
          to,
          duration,
          onUpdate,
          onFinish
        })
      }
    }
    const formattedValueRef = computed(() => {
      const formatted: string = round(
        displayedValueRef.value,
        props.precision
      ).toFixed(props.precision)
      const splitValue = formatted.split('.')
      const numberFormatter = new Intl.NumberFormat(mergedLocaleRef.value)
      const decimalSeparator = numberFormatter
        .formatToParts(0.5)
        .find(part => part.type === 'decimal')
        ?.value
      const integer = props.showSeparator
        ? numberFormatter.format(Number(splitValue[0]))
        : splitValue[0]
      const decimal = splitValue[1]
      return {
        integer,
        decimal,
        decimalSeparator
      }
    })
    function play(): void {
      if (animating)
        return
      animate()
    }
    onMounted(() => {
      watchEffect(() => {
        if (props.active)
          animate()
      })
    })
    const exposedMethods: NumberAnimationInst = { play }
    return {
      formattedValue: formattedValueRef,
      ...exposedMethods
    }
  },
  render() {
    const {
      formattedValue: { integer, decimal, decimalSeparator }
    } = this
    return [integer, decimal ? decimalSeparator : null, decimal]
  }
})

import { acceptHMRUpdate, defineStore } from 'pinia'
import { getRandomJoke, Joke } from '../api/jokes'
import { usePromise } from 'vue-promised'
import { ref, watch } from 'vue'

export const useJokes = defineStore('jokes-vue-promised', {
  state: () => {
    const promise = ref(getRandomJoke())

    watch(promise, () => {
      console.log('promise changed')
    })

    const promised = usePromise(promise)

    return {
      promise,
      ...promised,
      history: [] as Joke[],
    }
  },

  actions: {
    waitForJoke() {
      return this.promise
    },

    fetchJoke() {
      if (
        this.data &&
        // if the request below fails, avoid adding it twice
        !this.history.includes(this.data)
      ) {
        this.history.push(this.data)
      }

      console.log('fetching')
      // this.$state.promise = getRandomJoke()
      // Will fail because we initially had a ref
      this.promise = getRandomJoke()

      return this.$state.promise
    },
  },
})

export const useSetupJokes = defineStore('jokes-setup-vue-promised', () => {
  const history = ref<Joke[]>([])
  const promise = ref(getRandomJoke())
  watch(promise, () => {
    console.log('promise changed')
  })

  const promised = usePromise(promise)

  function fetchJoke() {
    if (
      promised.data.value &&
      // if the request below fails, avoid adding it twice
      !history.value.includes(promised.data.value)
    ) {
      history.value.push(promised.data.value)
    }

    console.log('fetching')
    // this.$state.promise = getRandomJoke()
    // Will fail because we initially had a ref
    promise.value = getRandomJoke()

    promise.value.then((joke) => {
      console.log('got', joke)
    })

    return promise.value
  }

  return {
    promise,
    ...promised,
    history,
    fetchJoke,
  }
})

if (import.meta.hot) {
