import { Transition, computed, getCurrentInstance, h } from 'vue'

import QSpinner from '../spinner/QSpinner.js'

import { createComponent } from '../../utils/private.create/create.js'
import useDark, {
  useDarkProps
} from '../../composables/private.use-dark/use-dark.js'
import useTransition, {
  useTransitionProps
} from '../../composables/private.use-transition/use-transition.js'

export default createComponent({
  name: 'QInnerLoading',

  props: {
    ...useDarkProps,
    ...useTransitionProps,

    showing: Boolean,
    color: String,

    size: {
      type: [String, Number],
      default: '42px'
    },

    label: String,
    labelClass: String,
    labelStyle: [String, Array, Object]
  },

  setup(props, { slots }) {
    const vm = getCurrentInstance()
    const isDark = useDark(props, vm.proxy.$q)

    const { transitionProps, transitionStyle } = useTransition(props)

    const classes = computed(
      () =>
        'q-inner-loading q--avoid-card-border absolute-full column flex-center' +
        (isDark.value ? ' q-inner-loading--dark' : '')
    )

    const labelClass = computed(
      () =>
        'q-inner-loading__label' +
        (props.labelClass !== void 0 ? ` ${props.labelClass}` : '')
    )

    function getInner() {
      const child = [
        h(QSpinner, {
          size: props.size,
          color: props.color
        })
      ]

      if (props.label !== void 0) {
        child.push(
          h(
            'div',
            {
              class: labelClass.value,
              style: props.labelStyle
            },
            [props.label]
          )
        )
      }

      return child
    }

    function getContent() {
      return props.showing
        ? h(
            'div',
            { class: classes.value, style: transitionStyle.value },
            slots.default !== void 0 ? slots.default() : getInner()
          )
        : null
    }

    return () => h(Transition, transitionProps.value, getContent)
  }
})

import { computed, getCurrentInstance, h, ref, watch } from 'vue'

import QDialog from '../dialog/QDialog.js'
import QMenu from '../menu/QMenu.js'

import useAnchor, {
  useAnchorProps
} from '../../composables/private.use-anchor/use-anchor.js'

import { createComponent } from '../../utils/private.create/create.js'
import { injectProp } from '../../utils/private.inject-obj-prop/inject-obj-prop.js'

export default createComponent({
  name: 'QPopupProxy',

  props: {
    ...useAnchorProps,

    breakpoint: {
      type: [String, Number],
      default: 450
    }
  },

  emits: ['show', 'hide'],

  setup(props, { slots, emit, attrs }) {
    const { proxy } = getCurrentInstance()
    const { $q } = proxy

    const showing = ref(false)
    const popupRef = ref(null)
    const breakpoint = computed(() => Number.parseInt(props.breakpoint, 10))

    const { canShow } = useAnchor({ showing, avoidEmit: true })

    function getType() {
      return $q.screen.width < breakpoint.value ||
        $q.screen.height < breakpoint.value
        ? 'dialog'
        : 'menu'
    }

    const type = ref(getType())

    const popupProps = computed(() =>
      type.value === 'menu' ? { maxHeight: '99vh' } : {}
    )

    watch(
      () => getType(),
      val => {
        if (!showing.value) type.value = val
      }
    )

    function onShow(evt) {
      showing.value = true
      emit('show', evt)
    }

    function onHide(evt) {
      showing.value = false
      type.value = getType()
      emit('hide', evt)
    }

    // expose public methods
    Object.assign(proxy, {
      show(evt) {
        if (canShow(evt)) popupRef.value.show(evt)
      },
      hide(evt) {
        popupRef.value.hide(evt)
      },
      toggle(evt) {
        popupRef.value.toggle(evt)
      }
    })

    injectProp(proxy, 'currentComponent', () => ({
      type: type.value,
      ref: popupRef.value
    }))

    return () => {
      const data = {
        ref: popupRef,
        ...popupProps.value,
        ...attrs,
        onShow,
        onHide
      }

      let component

      if (type.value === 'dialog') {
        component = QDialog
      } else {
        component = QMenu
        Object.assign(data, {
          target: props.target,
          contextMenu: props.contextMenu,
          noParentEvent: true,
          separateClosePopup: true
        })
      }

      return h(component, data, slots.default)
    }
  }
})

import Vue from 'vue';
import Main from './main.vue';
import { PopupManager } from 'element-ui/src/utils/popup';
import { isVNode } from 'element-ui/src/utils/vdom';
import { isObject } from 'element-ui/src/utils/types';
let MessageConstructor = Vue.extend(Main);

let instance;
let instances = [];
let seed = 1;

const Message = function(options) {
  if (Vue.prototype.$isServer) return;
  options = options || {};
  if (typeof options === 'string') {
    options = {
      message: options
    };
  }
  let userOnClose = options.onClose;
  let id = 'message_' + seed++;

  options.onClose = function() {
    Message.close(id, userOnClose);
  };
  instance = new MessageConstructor({
    data: options
  });
  instance.id = id;
  if (isVNode(instance.message)) {
    instance.$slots.default = [instance.message];
    instance.message = null;
  }
  instance.$mount();
  document.body.appendChild(instance.$el);
  let verticalOffset = options.offset || 20;
  instances.forEach(item => {
    verticalOffset += item.$el.offsetHeight + 16;
  });
  instance.verticalOffset = verticalOffset;
  instance.visible = true;
  instance.$el.style.zIndex = PopupManager.nextZIndex();
  instances.push(instance);
  return instance;
};

['success', 'warning', 'info', 'error'].forEach(type => {
  Message[type] = (options) => {
    if (isObject(options) && !isVNode(options)) {
      return Message({
        ...options,
        type
      });
    }
    return Message({
      type,
      message: options
    });
  };
});

Message.close = function(id, userOnClose) {
  let len = instances.length;
  let index = -1;
  let removedHeight;
  for (let i = 0; i < len; i++) {
    if (id === instances[i].id) {
      removedHeight = instances[i].$el.offsetHeight;
      index = i;
      if (typeof userOnClose === 'function') {
        userOnClose(instances[i]);
      }
      instances.splice(i, 1);
      break;
    }
  }
  if (len <= 1 || index === -1 || index > instances.length - 1) return;
  for (let i = index; i < len - 1 ; i++) {
    let dom = instances[i].$el;
    dom.style['top'] =
      parseInt(dom.style['top'], 10) - removedHeight - 16 + 'px';
  }
};

Message.closeAll = function() {
  for (let i = instances.length - 1; i >= 0; i--) {
    instances[i].close();
  }
};

export default Message;

import { computed } from 'vue'
import { useData, useRoute } from 'vitepress'
import { ensureStartingSlash } from '../utils'
import { useLang } from './lang'

export const useSidebar = () => {
  const route = useRoute()
  const { site, page } = useData()
  const lang = useLang()
  if (!page.value) {
    return {
      sidebars: computed(() => []),
      hasSidebar: computed(() => false),
    }
  }
  const sidebars = computed(() => {
    if (page.value.frontmatter.sidebar === false) return []
    const sidebars = getSidebarConfig(
      site.value.themeConfig.sidebars,
      route.data.relativePath,
      lang.value
    )
    return sidebars
  })

  return {
    sidebars,
    hasSidebar: computed(() => sidebars.value.length > 0),
  }
}

export function isSideBarConfig(sidebar) {
  return sidebar === false || sidebar === 'auto' || Array.isArray(sidebar)
}
export function isSideBarGroup(item) {
  return item.children !== undefined
}
export function isSideBarEmpty(sidebar) {
  return Array.isArray(sidebar) ? sidebar.length === 0 : !sidebar
}

type SidebarItem = {
  text: string
  link: string
}

type SidebarConfig = SidebarItem[]

type Sidebar =
  | {
      [key: string]: SidebarConfig
    }
  | false
  | 'auto'

export function getSidebarConfig(sidebar: Sidebar, path: string, lang: string) {
  if (sidebar === false || Array.isArray(sidebar) || sidebar === 'auto') {
    return []
  }

  path = ensureStartingSlash(path)
  for (const dir in sidebar) {
    // make sure the multi sidebar key starts with slash too
    if (path.startsWith(ensureStartingSlash(`${lang}${dir}`))) {
      return sidebar[dir][lang]
    }
  }
  return []
}

export function getFlatSideBarLinks(sidebar) {
  return sidebar.reduce((links, item) => {
    if (item.link) {
      links.push({ text: item.text, link: item.link })
    }
    if (isSideBarGroup(item)) {
      links = [...links, ...getFlatSideBarLinks(item.children)]
    }
    return links
  }, [])
}

const vueSticky = {}
let listenAction
vueSticky.install = Vue => {
  Vue.directive('sticky', {
    inserted(el, binding) {
      const params = binding.value || {}
      const stickyTop = params.stickyTop || 0
      const zIndex = params.zIndex || 1000
      const elStyle = el.style

      elStyle.position = '-webkit-sticky'
      elStyle.position = 'sticky'
      // if the browser support css sticky（Currently Safari, Firefox and Chrome Canary）
      // if (~elStyle.position.indexOf('sticky')) {
      //     elStyle.top = `${stickyTop}px`;
      //     elStyle.zIndex = zIndex;
      //     return
      // }
      const elHeight = el.getBoundingClientRect().height
      const elWidth = el.getBoundingClientRect().width
      elStyle.cssText = `top: ${stickyTop}px; z-index: ${zIndex}`

      const parentElm = el.parentNode || document.documentElement
      const placeholder = document.createElement('div')
      placeholder.style.display = 'none'
      placeholder.style.width = `${elWidth}px`
      placeholder.style.height = `${elHeight}px`
      parentElm.insertBefore(placeholder, el)

      let active = false

      const getScroll = (target, top) => {
        const prop = top ? 'pageYOffset' : 'pageXOffset'
        const method = top ? 'scrollTop' : 'scrollLeft'
        let ret = target[prop]
        if (typeof ret !== 'number') {
          ret = window.document.documentElement[method]
        }
        return ret
      }

      const sticky = () => {
        if (active) {
          return
        }
        if (!elStyle.height) {
          elStyle.height = `${el.offsetHeight}px`
        }

        elStyle.position = 'fixed'
        elStyle.width = `${elWidth}px`
        placeholder.style.display = 'inline-block'
        active = true
      }

      const reset = () => {
        if (!active) {
          return
        }

        elStyle.position = ''
        placeholder.style.display = 'none'
        active = false
      }

      const check = () => {
        const scrollTop = getScroll(window, true)
        const offsetTop = el.getBoundingClientRect().top
        if (offsetTop < stickyTop) {
          sticky()
        } else {
          if (scrollTop < elHeight + stickyTop) {
            reset()
          }
        }
      }
      listenAction = () => {
        check()
      }

      window.addEventListener('scroll', listenAction)
    },

    unbind() {
      window.removeEventListener('scroll', listenAction)
    }
  })
}

export default vueSticky

import { computed } from 'vue'

import { toJalaali } from '../../utils/date/private.persian.js'
import { pad } from '../../utils/format/format.js'

const calendars = ['gregorian', 'persian']

export const useDatetimeProps = {
  // should define modelValue in the target component

  mask: {
    type: String
  },
  locale: Object,

  calendar: {
    type: String,
    validator: v => calendars.includes(v),
    default: 'gregorian'
  },

  landscape: Boolean,

  color: String,
  textColor: String,

  square: Boolean,
  flat: Boolean,
  bordered: Boolean,

  readonly: Boolean,
  disable: Boolean
}

export const useDatetimeEmits = ['update:modelValue']

export function getDayHash(date) {
  return date.year + '/' + pad(date.month) + '/' + pad(date.day)
}

export default function useDatetime(props, $q) {
  const editable = computed(() => !props.disable && !props.readonly)
  const tabindex = computed(() => (editable.value ? 0 : -1))

  const headerClass = computed(() => {
    const cls = []
    if (props.color !== void 0) cls.push(`bg-${props.color}`)
    if (props.textColor !== void 0) cls.push(`text-${props.textColor}`)
    return cls.join(' ')
  })

  function getLocale() {
    return props.locale !== void 0
      ? { ...$q.lang.date, ...props.locale }
      : $q.lang.date
  }

  function getCurrentDate(dateOnly) {
    const d = new Date()
    const timeFill = dateOnly ? null : 0

    if (props.calendar === 'persian') {
      const jDate = toJalaali(d)
      return {
        year: jDate.jy,
        month: jDate.jm,
        day: jDate.jd
      }
    }

    return {
      year: d.getFullYear(),
      month: d.getMonth() + 1,
      day: d.getDate(),
      hour: timeFill,
      minute: timeFill,
      second: timeFill,
      millisecond: timeFill
    }
  }

  return {
    editable,
    tabindex,
    headerClass,

    getLocale,
    getCurrentDate
  }
}

import { computed } from 'vue'

import { isNumber } from '../../utils/is/is.js'

export const useTableColumnSelectionProps = {
  visibleColumns: Array
}

export function useTableColumnSelection(
  props,
  computedPagination,
  hasSelectionMode
) {
  const colList = computed(() => {
    if (props.columns !== void 0) {
      return props.columns
    }

    // we infer columns from first row
    const row = props.rows[0]

    return row !== void 0
      ? Object.keys(row).map(name => ({
          name,
          label: name.toUpperCase(),
          field: name,
          align: isNumber(row[name]) ? 'right' : 'left',
          sortable: true
        }))
      : []
  })

  const computedCols = computed(() => {
    const { sortBy, descending } = computedPagination.value

    const cols =
      props.visibleColumns !== void 0
        ? colList.value.filter(
            col => col.required || props.visibleColumns.includes(col.name)
          )
        : colList.value

    return cols.map(col => {
      const align = col.align || 'right'
      const alignClass = `text-${align}`

      return {
        ...col,
        align,
        __iconClass: `q-table__sort-icon q-table__sort-icon--${align}`,
        __thClass:
          alignClass +
          (col.headerClasses !== void 0 ? ' ' + col.headerClasses : '') +
          (col.sortable ? ' sortable' : '') +
          (col.name === sortBy
            ? ` sorted ${descending ? 'sort-desc' : ''}`
            : ''),

        __tdStyle:
          col.style !== void 0
            ? typeof col.style !== 'function'
              ? () => col.style
              : col.style
            : () => null,

        __tdClass:
          col.classes !== void 0
            ? typeof col.classes !== 'function'
              ? () => alignClass + ' ' + col.classes
              : row => alignClass + ' ' + col.classes(row)
            : () => alignClass
      }
    })
  })

  const computedColsMap = computed(() => {
    const names = {}
    computedCols.value.forEach(col => {
      names[col.name] = col
    })
    return names
  })

  const computedColspan = computed(() =>
    props.tableColspan !== void 0
      ? props.tableColspan
      : computedCols.value.length + (hasSelectionMode.value ? 1 : 0)
  )

  return {
    colList,
    computedCols,
    computedColsMap,
    computedColspan
  }
}

import Main from '~/components/main'
import QuickLinks from '~/components/quick-links'
import Reload from '~/components/reload'
import Section from '~/components/section'
import { mergeData } from 'vue-functional-data-merge'
import { bootstrapVersion, vueVersion } from '~/content'

// @vue/component
export default {
  name: 'BVMainDocs',
  functional: true,
  props: {
    tag: {
      type: String,
      default: 'main'
    },
    titleLead: {
      type: String,
      default: ''
    },
    body: {
      type: String,
      default: ''
    },
    meta: {
      type: Object,
      default: null
    },
    loadError: {
      type: Boolean,
      default: false
    }
  },
  render(h, { props, data, children }) {
    const { tag, titleLead, body, meta, loadError } = props
    const { version } = meta || {}

    // Lead section
    const $leadSection = h(Section, {
      props: { tag: 'header', play: false },
      domProps: { innerHTML: titleLead || '' }
    })

    // Available since section
    let $availableSinceSection = h()
    if (version) {
      $availableSinceSection = h(Section, { props: { play: false } }, [
        h('p', { staticClass: 'font-italic' }, [
          'Available in BootstrapVue since ',
          h('code', { staticClass: 'text-nowrap' }, `v${version}`)
        ])
      ])
    }

    // Error handler
    const $error = loadError ? h(Reload) : h()

    // Quick links
    const $quickLinks = h(QuickLinks)

    // Body section
    const $bodySectionContent = h({
      delimiters: ['[[', ']]'], // change the delimiters to avoid conflicts with code examples
      data() {
        return {
          bootstrapVersion,
          vueVersion
        }
      },
      template: `<div>${body}</div>`
    })

    const $bodySection = h(
      Section,
      {
        props: { play: true }
      },
      [$bodySectionContent]
    )

    return h(Main, mergeData(data, { props: { tag } }), [
      $leadSection,
      $error,
      $availableSinceSection,
      $quickLinks,
      $bodySection,
      children
    ])
  }
}

import { join } from 'node:path'
import fse from 'fs-extra'

import { build as viteBuild } from 'vite'
import { rolldown, watch as rolldownWatch } from 'rolldown'

import { progress } from './utils/logger.js'

const cordovaWWW = join('src-cordova', 'www')
const capacitorWWW = join('src-capacitor', 'www')

export class AppTool {
  argv
  ctx

  constructor({ argv, ctx }) {
    this.argv = argv
    this.ctx = ctx
  }

  async buildWithVite(threadName, viteConfig) {
    const done = progress({
      tool: 'Vite',
      waitAction: 'Compiling',
      doneAction: 'Compiled',
      target: threadName
    })

    await viteBuild(viteConfig)
    done()
  }

  watchWithRolldown(threadName, rolldownConfig, onRebuildSuccess) {
    const { promise, resolve } = Promise.withResolvers()
    const watcher = rolldownWatch({
      ...rolldownConfig,
      watch: {
        exclude: /node_modules/
      }
    })

    let isFirstBuild = true
    let done

    watcher.on('event', event => {
      if (event.code === 'START') {
        done = progress({
          tool: 'Rolldown',
          waitAction: 'Compiling',
          doneAction: 'Compiled',
          target: threadName
        })
      } else if (event.code === 'BUNDLE_END') {
        event.result.close()
        done()

        if (isFirstBuild) {
          isFirstBuild = false
          resolve(watcher)
        } else onRebuildSuccess()
      } else if (event.code === 'ERROR') {
        console.error(event.error)
        event.result.close()
      }
    })

    return promise
  }

  async buildWithRolldown(threadName, rolldownConfig) {
    const done = progress({
      tool: 'Rolldown',
      waitAction: 'Compiling',
      doneAction: 'Compiled',
      target: threadName
    })

    const bundle = await rolldown(rolldownConfig)
    await bundle.write(rolldownConfig.output)
    await bundle.close()

    done()
  }

  cleanArtifacts(dir = this.quasarConf.build.distDir) {
    if (dir.endsWith(cordovaWWW)) {
      fse.emptyDirSync(dir)
    } else if (dir.endsWith(capacitorWWW)) {
      const { appPaths } = this.ctx

      fse.emptyDirSync(dir)
      fse.copySync(
        appPaths.resolve.cli('templates/capacitor/common/www'),
        appPaths.resolve.capacitor('www')
      )
    } else {
      fse.removeSync(dir)
    }
  }
}

import { computed, ref } from 'vue'
import { isFunction } from '@element-plus/utils'

import type { Ref } from 'vue'
import type { Tree, TreeKey, TreeNode, TreeProps } from '../types'

// When the data volume is very large using filter will cause lag
// I haven't found a better way to optimize it for now
// Maybe this problem should be left to the server side
export function useFilter(props: TreeProps, tree: Ref<Tree | undefined>) {
  const hiddenNodeKeySet = ref<Set<TreeKey>>(new Set([]))
  const hiddenExpandIconKeySet = ref<Set<TreeKey>>(new Set([]))

  const filterable = computed(() => {
    return isFunction(props.filterMethod)
  })

  function doFilter(query: string) {
    if (!filterable.value) {
      return
    }
    const expandKeySet = new Set<TreeKey>()
    const hiddenExpandIconKeys = hiddenExpandIconKeySet.value
    const hiddenKeys = hiddenNodeKeySet.value
    const family: TreeNode[] = []
    const nodes = tree.value?.treeNodes || []
    const filter = props.filterMethod
    hiddenKeys.clear()
    function traverse(nodes: TreeNode[]) {
      nodes.forEach((node) => {
        family.push(node)
        if (filter?.(query, node.data, node)) {
          family.forEach((member) => {
            expandKeySet.add(member.key)
            member.expanded = true
          })
        } else {
          node.expanded = false
          if (node.isLeaf) {
            hiddenKeys.add(node.key)
          }
        }
        const children = node.children
        if (children) {
          traverse(children)
        }
        if (!node.isLeaf) {
          if (!expandKeySet.has(node.key)) {
            hiddenKeys.add(node.key)
          } else if (children) {
            // If all child nodes are hidden, then the expand icon will be hidden
            let allHidden = true
            for (const childNode of children) {
              if (!hiddenKeys.has(childNode.key)) {
                allHidden = false
                break
              }
            }
            if (allHidden) {
              hiddenExpandIconKeys.add(node.key)
            } else {
              hiddenExpandIconKeys.delete(node.key)
            }
          }
        }
        family.pop()
      })
    }
    traverse(nodes)
    return expandKeySet
  }

  function isForceHiddenExpandIcon(node: TreeNode): boolean {
    return hiddenExpandIconKeySet.value.has(node.key)
  }

  return {
    hiddenExpandIconKeySet,
    hiddenNodeKeySet,
    doFilter,
    isForceHiddenExpandIcon,
  }
}

import { getArgv } from '../utils/get-argv.js'
import { log } from '../utils/logger.js'

const argv = getArgv({
  entry: { type: 'boolean', short: 'e', default: false },
  cache: { type: 'boolean', short: 'c', default: false },
  dist: { type: 'boolean', short: 'd', default: false },
  qconf: { type: 'boolean', short: 'q', default: false },
  'no-color': { type: 'boolean' },
  help: { type: 'boolean', short: 'h' }
})

if (argv.help) {
  console.log(`
  Description
    Cleans all build artifacts
    (dev/build cache, /dist folder & entry points)

  Usage
    $ quasar clean

  Options
    --entry, -e    Cleans generated entry points only
    --cache, -c    Cleans dev/build cache only
    --dist, -d     Cleans /dist folder only
    --qconf, -q    Cleans temporary compiled quasar.config files
                      (used for issue investigation)
    --no-color     Disable colored output
    --help, -h     Displays this message
  `)

  argv.__warn?.()
  process.exit(0)
}

import fse from 'fs-extra'
import { getCtx } from '../utils/get-ctx.js'

const { appPaths } = getCtx()

console.log()

const cleanAll =
  argv.entry !== true &&
  argv.cache !== true &&
  argv.dist !== true &&
  argv.qconf !== true

if (cleanAll || argv.entry) {
  fse.removeSync(appPaths.resolve.app('.quasar'))
  log('Cleaned generated entry points')
}

if (cleanAll || argv.cache) {
  fse.removeSync(appPaths.cacheDir)
  log('Cleaned dev/build cache')
}

if (cleanAll || argv.dist) {
  // we empty the dist folder
  // (will not work if build > distDir was changed outside of it)
  fse.emptyDirSync(appPaths.resolve.app('dist'))
  log('Cleaned /dist folder')
}

if (cleanAll || argv.qconf) {
  const { globSync } = await import('tinyglobby')
  const fileList = globSync(['quasar.config.*.temporary.compiled.*'], {
    cwd: appPaths.appDir
  })

  fileList.forEach(file => {
    fse.removeSync(appPaths.resolve.app(file))
  })

  log(
    `Cleaned ${fileList.length} temporary compiled quasar.config file${fileList.length === 1 ? '' : 's'}`
  )
}

console.log()

import { getArgv } from '../utils/get-argv.js'

const argv = getArgv({
  'no-color': { type: 'boolean' },
  help: { type: 'boolean', short: 'h' }
})

function showHelp() {
  console.log(`
  Description
    Manage Quasar App Extensions

  Usage
    # display list of installed extensions
    $ quasar ext

    # Add Quasar App Extension
    $ quasar ext add <ext-id>

    # Remove Quasar App Extension
    $ quasar ext remove <ext-id>

    # Add Quasar App Extension, but
    # skip installing the npm package
    # (assumes it's already installed)
    $ quasar ext invoke <ext-id>

    # Remove Quasar App Extension, but
    # skip uninstalling the npm package
    $ quasar ext uninvoke <ext-id>

  Options
    --no-color   Disable colored output
    --help, -h   Displays this message
  `)
}

if (argv.help) {
  showHelp()
  argv.__warn?.()
  process.exit(0)
}

import { log, warn, dot } from '../utils/logger.js'
import { green } from 'kolorist'

if (argv._.length !== 0 && argv._.length !== 2) {
  console.log()
  warn(`Wrong number of parameters (${argv._.length}).`)
  showHelp()
  process.exit(1)
}

const { getCtx } = await import('../utils/get-ctx.js')
const { appExt } = getCtx({
  mode: 'spa',
  debug: false,
  prod: true
})

if (argv._.length === 0) {
  if (appExt.extensionList.length === 0) {
    log(' No App Extensions are installed')
    log(' You can look for "quasar-app-extension-*" in npm registry.')
  } else {
    console.log('Installed App Extensions:')

    for (const ext of appExt.extensionList) {
      const prompts = ext.getPrompts()
      const hasPrompts = Object.keys(prompts).length !== 0

      console.log(
        `  ${green(dot)} ${ext.extId}${hasPrompts ? ' (with prompts)' : ''}`
      )

      if (hasPrompts) {
        console.log(JSON.stringify(prompts, null, 2))
        console.log()
      }
    }
  }
} else {
  const [action, extName] = argv._

  if (!['add', 'remove', 'invoke', 'uninvoke'].includes(action)) {
    console.log()
    warn(`Unknown action specified (${action}).`)
    showHelp()
    process.exit(1)
  }

  const ext = appExt.createInstance(extName)

  await ext[action === 'add' || action === 'invoke' ? 'install' : 'uninstall'](
    action === 'invoke' || action === 'uninvoke'
  )
}

import { getArgv } from '../utils/get-argv.js'

const argv = getArgv(
  {
    'no-color': { type: 'boolean' }
  },
  { strict: false }
)

const extId = argv._[0]
const cmd = argv._[1]

if (!extId) {
  console.log(`
  Description
    Run app extension provided commands

  Usage
    $ quasar run <extension-id> <cmd> [...args]

    $ quasar run iconify create pic -s --mark some_file
        # Note: "iconify" is an example and not a real extension.
        # Looks for installed extension called "iconify"
        # (quasar-app-extension-iconify extension package)
        # and runs its custom defined "create" command
        # with "pic" argument and "-s --mark some_file" params

  Options
    --no-color  Disable colored output
  `)

  process.exit(0)
}

import { log, warn } from '../utils/logger.js'
import { getExtensionLogger } from '../app-extension/logger.js'

import { getCtx } from '../utils/get-ctx.js'

const { appExt } = getCtx()

const ext = appExt.getInstance(extId)
if (ext === void 0) {
  warn()
  getExtensionLogger(extId).warn('No such App Extension is installed')
  warn()
  process.exit(1)
}

const hooks = await ext.run()

const list = () => {
  if (Object.keys(hooks.commands).length === 0) {
    ext.logger.warn(`App Extension has no commands registered`)
    return
  }

  const cmdList = Object.keys(hooks.commands).join(' | ')
  ext.logger.log(`Command list: ${cmdList}`)
}

if (!cmd) {
  list()
  process.exit(0)
}

const fn = hooks.commands[cmd]
if (!fn) {
  list()
  warn()
  ext.logger.warn(`App Extension has no command called "${cmd}"`)
  warn()
  process.exit(1)
}

ext.logger.log(`Running App Extension command "${cmd}"`)
log()

process.argv = [
  ...process.argv.slice(0, 2),
  ...process.argv.slice(4).filter(arg => arg !== '--no-color')
]

await fn(process.argv)
